import math, string, re

def analyse_password(password):
    pool = 0
    classes = []
    if re.search(r'[a-z]', password): pool += 26; classes.append('lowercase')
    if re.search(r'[A-Z]', password): pool += 26; classes.append('UPPERCASE')
    if re.search(r'[0-9]', password): pool += 10; classes.append('digits')
    if re.search(r'[^a-zA-Z0-9]', password): pool += 32; classes.append('symbols')

    entropy = len(password) * math.log2(pool) if pool else 0

    # Check for common patterns
    warnings = []
    if len(password) < 8: warnings.append('Too short (min 8)')
    if password.lower() in ['password', '123456', 'qwerty']: warnings.append('Common password!')
    if re.search(r'(.)\1{2,}', password): warnings.append('Repeated characters')
    if re.search(r'(012|123|234|345|456|567|678|789|abc|bcd)', password.lower()): warnings.append('Sequential pattern')

    strength = 'VERY WEAK' if entropy < 30 else 'WEAK' if entropy < 45 else 'FAIR' if entropy < 60 else 'STRONG' if entropy < 80 else 'VERY STRONG'

    print(f'Password: {password}')
    print(f'Length: {len(password)} | Pool: {pool} | Classes: {", ".join(classes)}')
    print(f'Entropy: {entropy:.1f} bits -> {strength}')
    if warnings: print(f'Warnings: {", ".join(warnings)}')
    print()

for pwd in ['pass', 'password', 'Password1', 'P@ssw0rd!x', 'Xy7$kL9!mN2#qR', 'correct horse battery staple']:
    analyse_password(pwd)

import hashlib, time

def build_rainbow_table(wordlist):
    table = {}
    for word in wordlist:
        for algo in ['md5', 'sha1', 'sha256']:
            h = hashlib.new(algo, word.encode()).hexdigest()
            table[h] = (word, algo)
    return table

def rainbow_lookup(target_hash, table):
    if target_hash in table:
        return table[target_hash]
    return None

