class PasswordHistory:
    def __init__(self, history_size=5): self.users = {}; self.hs = history_size
    def register(self, u, p):
        s = os.urandom(16); h = hashlib.pbkdf2_hmac('sha256',p.encode(),s,10000)
        self.users[u] = {'salt':s,'hash':h,'history':[(s,h)]}
    def change_password(self, username, new_pw):
        if username not in self.users: return (False, 'User not found')
        u = self.users[username]
        for old_salt, old_hash in u['history']:
            if hashlib.pbkdf2_hmac('sha256', new_pw.encode(), old_salt, 10000) == old_hash:
                return (False, 'Password was recently used')
        s = os.urandom(16); h = hashlib.pbkdf2_hmac('sha256', new_pw.encode(), s, 10000)
        u['salt'] = s; u['hash'] = h
        u['history'].append((s, h))
        if len(u['history']) > self.hs: u['history'] = u['history'][-self.hs:]
        return (True, 'Password changed')

