import hashlib, os, secrets, time, hmac as hm
class FullAuth:
    def __init__(self): self.users = {}; self.tokens = {}
    def _hash(self, p, s=None):
        if s is None: s = os.urandom(16)
        return s, hashlib.pbkdf2_hmac('sha256', p.encode(), s, 10000)
    def register(self, u, p):
        if u in self.users: return (False, 'Exists')
        if len(p) < 8: return (False, 'Too short')
        s, h = self._hash(p)
        self.users[u] = {'salt':s, 'hash':h}
        return (True, 'Registered')
    def login(self, u, p):
        if u not in self.users: self._hash(p); return (False, 'Invalid')
        s, h = self._hash(p, self.users[u]['salt'])
        if hm.compare_digest(h, self.users[u]['hash']): return (True, 'Login successful')
        return (False, 'Invalid')
    def reset_request(self, u):
        token = secrets.token_urlsafe(32)
        th = hashlib.sha256(token.encode()).hexdigest()
        self.tokens[th] = {'user':u,'exp':time.time()+3600}
        return token
    def reset_confirm(self, token, new_pw):
        th = hashlib.sha256(token.encode()).hexdigest()
        if th not in self.tokens: return (False, 'Invalid token')
        t = self.tokens.pop(th)
        if time.time() > t['exp']: return (False, 'Expired')
        s, h = self._hash(new_pw)
        self.users[t['user']] = {'salt':s,'hash':h}
        return (True, 'Password reset')
